function calculateFairnessScore(inputData) {
  const { metrics, pass_threshold } = inputData;
  const scores = {};
  const failingMetrics = [];
  let compositeScore = 0;

  for (const [name, m] of Object.entries(metrics)) {
    let normalized;
    let status;

    if (m.ideal === 0) {
      normalized = Math.max(0, Math.round((1 - m.value / m.max_acceptable) * 100) / 100);
      status = m.value <= m.max_acceptable ? "PASS" : "FAIL";
    } else {
      const threshold = 1 - m.max_acceptable;
      normalized = Math.max(0, Math.round(((m.value - threshold) / m.max_acceptable) * 100) / 100);
      status = m.value >= threshold ? "PASS" : "FAIL";
    }

    scores[name] = { raw: m.value, normalized, status };
    compositeScore += normalized * m.weight;

    if (status === "FAIL") {
      failingMetrics.push(name);
    }
  }

  compositeScore = Math.round(compositeScore * 100) / 100;
  const overall = compositeScore >= pass_threshold ? "PASS" : "FAIL";

  let recommendation;
  if (failingMetrics.length === 0) {
    recommendation = "All metrics within acceptable thresholds";
  } else {
    const details = failingMetrics.map(name => {
      const m = metrics[name];
      if (m.ideal === 0) {
        return `${name} before deployment (${m.value} > ${m.max_acceptable} threshold)`;
      } else {
        return `${name} before deployment (${m.value} < ${1 - m.max_acceptable} threshold)`;
      }
    });
    recommendation = "Address " + details.join("; ");
  }

  return JSON.stringify({
    scores,
    composite_score: compositeScore,
    pass_threshold,
    overall,
    failing_metrics: failingMetrics,
    recommendation
  }, null, 2);
}

const input = JSON.parse(require('fs').readFileSync('/dev/stdin', 'utf8'));
console.log(calculateFairnessScore(input));
